INSERT INTO `pipelines` VALUES (1,'2026-03-20 14:25:14.001','2026-03-20 14:25:14.001','平台预置 VM 发布流水线','平台预置的 VM 应用部署流水线','{\"edges\":[],\"nodes\":[{\"config\":{\"container_name\":\"${inputs.app_name}\",\"host\":\"${inputs.resource_host}\",\"image_name\":\"${inputs.image_name}\",\"image_tag\":\"${inputs.image_tag}\",\"port\":\"${inputs.resource_port}\",\"run_args\":\"-d\",\"user\":\"root\"},\"id\":\"deploy\",\"name\":\"Docker Deploy\",\"type\":\"docker-run\"}],\"version\":\"2.0\"}',1,1,1,'production',0,0,1),(2,'2026-03-20 14:25:14.003','2026-03-20 14:25:14.003','平台预置 K8s 发布流水线','平台预置的 Kubernetes 应用部署流水线','{\"edges\":[],\"nodes\":[{\"config\":{\"command\":\"echo deploying ${inputs.resource_name}\"},\"id\":\"deploy\",\"name\":\"Kubernetes Deploy\",\"type\":\"kubernetes\"}],\"version\":\"2.0\"}',1,1,1,'production',0,0,1),(3,'2026-03-20 14:25:14.005','2026-03-20 14:25:14.005','平台预置 vLLM VM 发布流水线','平台预置的 vLLM VM 发布流水线','{\"edges\":[],\"nodes\":[{\"config\":{\"host\":\"${inputs.resource_host}\",\"port\":\"${inputs.resource_port}\",\"script\":\"set -e\\nRUNTIME_BIN=\\\"\\\"\\nSUDO_PASSWORD=\\\"\\\"\\nUSE_SUDO=\\\"false\\\"\\nif [ -n \\\"${EASYDO_REMOTE_AUTH_PASSWORD_B64:-}\\\" ] \\u0026\\u0026 command -v base64 \\u003e/dev/null 2\\u003e\\u00261; then\\n  SUDO_PASSWORD=\\\"$(printf \'%s\' \\\"${EASYDO_REMOTE_AUTH_PASSWORD_B64}\\\" | base64 -d 2\\u003e/dev/null || true)\\\"\\nfi\\nfor candidate in docker podman nerdctl; do\\n  if command -v \\\"$candidate\\\" \\u003e/dev/null 2\\u003e\\u00261; then\\n    if \\\"$candidate\\\" version \\u003e/dev/null 2\\u003e\\u00261; then\\n      RUNTIME_BIN=\\\"$candidate\\\"\\n      break\\n    fi\\n    # 当当前 SSH 用户没有直接访问容器运行时权限时，回退到 sudo 密码模式。\\n    if [ -n \\\"$SUDO_PASSWORD\\\" ] \\u0026\\u0026 command -v sudo \\u003e/dev/null 2\\u003e\\u00261 \\u0026\\u0026 printf \'%s\\\\n\' \\\"$SUDO_PASSWORD\\\" | sudo -S -k \\\"$candidate\\\" version \\u003e/dev/null 2\\u003e\\u00261; then\\n      RUNTIME_BIN=\\\"$candidate\\\"\\n      USE_SUDO=\\\"true\\\"\\n      break\\n    fi\\n  fi\\ndone\\nif [ -z \\\"$RUNTIME_BIN\\\" ]; then\\n  echo \\\"未检测到可用容器运行时（docker/podman/nerdctl）\\\" \\u003e\\u00262\\n  exit 1\\nfi\\nMODEL_REF=\\\"${inputs.runtime_model_path}\\\"\\nif [ -z \\\"$MODEL_REF\\\" ]; then\\n  MODEL_REF=\\\"${inputs.model_path}\\\"\\nfi\\nif [ -z \\\"$MODEL_REF\\\" ]; then\\n  MODEL_REF=\\\"${inputs.model_source_ref}\\\"\\nfi\\nif [ -z \\\"$MODEL_REF\\\" ]; then\\n  echo \\\"缺少模型路径或模型来源标识\\\" \\u003e\\u00262\\n  exit 1\\nfi\\nIMAGE_REF=\\\"${inputs.image_name}:${inputs.image_tag}\\\"\\nCONTAINER_NAME=\\\"${inputs.app_name}\\\"\\nSERVE_PORT=\\\"${inputs.port}\\\"\\nSERVE_HOST=\\\"${inputs.host}\\\"\\nMOUNT_ARGS=\\\"\\\"\\nif [ -n \\\"${inputs.host_model_dir}\\\" ] \\u0026\\u0026 [ -n \\\"${inputs.container_model_dir}\\\" ]; then\\n  MOUNT_ARGS=\\\"--mount type=bind,src=${inputs.host_model_dir},dst=${inputs.container_model_dir}\\\"\\n  if [ \\\"${inputs.model_mount_readonly}\\\" = \\\"true\\\" ]; then\\n    MOUNT_ARGS=\\\"$MOUNT_ARGS,readonly\\\"\\n  fi\\nfi\\nVLLM_ARGS=\\\"--host ${inputs.host} --port ${inputs.port} --served-model-name ${inputs.served_model_name} --tensor-parallel-size ${inputs.tensor_parallel_size} --pipeline-parallel-size ${inputs.pipeline_parallel_size} --gpu-memory-utilization ${inputs.gpu_memory_utilization} --max-model-len ${inputs.max_model_len} --dtype ${inputs.dtype} --load-format ${inputs.load_format}\\\"\\nif [ -n \\\"${inputs.quantization}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --quantization ${inputs.quantization}\\\"; fi\\nif [ -n \\\"${inputs.download_dir}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --download-dir ${inputs.download_dir}\\\"; fi\\nif [ -n \\\"${inputs.swap_space}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --swap-space ${inputs.swap_space}\\\"; fi\\nif [ -n \\\"${inputs.cpu_offload_gb}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --cpu-offload-gb ${inputs.cpu_offload_gb}\\\"; fi\\nif [ -n \\\"${inputs.kv_cache_dtype}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --kv-cache-dtype ${inputs.kv_cache_dtype}\\\"; fi\\nif [ -n \\\"${inputs.block_size}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --block-size ${inputs.block_size}\\\"; fi\\nif [ -n \\\"${inputs.max_num_seqs}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --max-num-seqs ${inputs.max_num_seqs}\\\"; fi\\nif [ -n \\\"${inputs.max_num_batched_tokens}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --max-num-batched-tokens ${inputs.max_num_batched_tokens}\\\"; fi\\nif [ -n \\\"${inputs.revision}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --revision ${inputs.revision}\\\"; fi\\nif [ -n \\\"${inputs.tokenizer}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --tokenizer ${inputs.tokenizer}\\\"; fi\\nif [ -n \\\"${inputs.tokenizer_revision}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --tokenizer-revision ${inputs.tokenizer_revision}\\\"; fi\\nif [ -n \\\"${inputs.api_key}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --api-key ${inputs.api_key}\\\"; fi\\nif [ -n \\\"${inputs.uvicorn_log_level}\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --uvicorn-log-level ${inputs.uvicorn_log_level}\\\"; fi\\nif [ \\\"${inputs.enforce_eager}\\\" = \\\"true\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --enforce-eager\\\"; fi\\nif [ \\\"${inputs.disable_log_stats}\\\" = \\\"true\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --disable-log-stats\\\"; fi\\nif [ \\\"${inputs.enable_prefix_caching}\\\" = \\\"true\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --enable-prefix-caching\\\"; fi\\nif [ \\\"${inputs.enable_chunked_prefill}\\\" = \\\"true\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --enable-chunked-prefill\\\"; fi\\nif [ \\\"${inputs.trust_remote_code}\\\" = \\\"true\\\" ]; then VLLM_ARGS=\\\"$VLLM_ARGS --trust-remote-code\\\"; fi\\nRUNTIME_RUN_CMD=\\\"$RUNTIME_BIN run -d --name $CONTAINER_NAME --restart unless-stopped --gpus all --ipc=host -p ${inputs.port}:${inputs.port} $MOUNT_ARGS $IMAGE_REF vllm serve $MODEL_REF $VLLM_ARGS\\\"\\nif [ \\\"$USE_SUDO\\\" = \\\"true\\\" ]; then\\n  printf \'%s\\\\n\' \\\"$SUDO_PASSWORD\\\" | sudo -S -k \\\"$RUNTIME_BIN\\\" rm -f \\\"$CONTAINER_NAME\\\" \\u003e/dev/null 2\\u003e